const row = $('DB: Fetch Appointment + Tokens').first().json;
const tokenRes = $('Google: Refresh Token').first().json;
const tz = row.timezone || 'America/Chicago';
const scheduledAt = new Date(row.scheduled_at);
const dateStr = scheduledAt.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', timeZone: tz });
const timeStr = scheduledAt.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: tz });
const endAt = new Date(scheduledAt.getTime() + (row.duration_minutes || 60) * 60000);
const calId = row.calendar_id || 'primary';
const access_token = tokenRes.access_token || '';
const hasToken = !!access_token && !tokenRes.error;
const wh = $('Webhook: Calendar Sync Trigger').first().json.body;
return [{ json: {
  appointment_id: row.appointment_id,
  customer_phone: row.customer_phone,
  service_type: row.service_type,
  our_phone: row.our_phone,
  shop_name: row.shop_name,
  calId, dateStr, timeStr, tz, scheduledAt: scheduledAt.toISOString(),
  endAt: endAt.toISOString(),
  access_token, hasToken,
  tenantId: wh.tenantId,
  appointmentId: wh.appointmentId,
  eventSummary: row.service_type + ' \u2014 ' + (row.customer_phone || 'Customer'),
  eventDescription: 'AutoShop AI booking. Service: ' + row.service_type,
} }];

const data = $('Code: Build Event Body').first().json;
const calResult = $('Google Calendar: Create Event').first().json;
const calendarSynced = !!(calResult.id && !calResult.error);
const googleEventId = calResult.id || '';
const calendarSyncError = calResult.error ? JSON.stringify(calResult.error).substring(0,200) : '';
const smsText = calendarSynced
  ? `Your ${data.service_type} appt is confirmed for ${data.dateStr} at ${data.timeStr}. Added to our calendar! - ${data.shop_name}`
  : `Your ${data.service_type} appt is confirmed for ${data.dateStr} at ${data.timeStr}. See you then! - ${data.shop_name}`;
return [{ json: {
  customerPhone: data.customer_phone,
  ourPhone: data.our_phone,
  googleEventId, calendarSynced, calendarSyncError, smsText,
  tenantId: data.tenantId,
  appointmentId: data.appointmentId,
} }];

parameters.query:
SET LOCAL app.current_tenant_id = '{{ $json.tenantId }}';
UPDATE appointments
SET
  google_event_id = CASE WHEN '{{ $json.googleEventId }}' = '' THEN NULL ELSE '{{ $json.googleEventId }}' END,
  calendar_synced = {{ $json.calendarSynced }}
WHERE id = '{{ $json.appointmentId }}'::uuid;

