const smsResult = $('Twilio: Send Confirmation SMS').first().json;
const sid = smsResult?.sid || null;
const errorCode = smsResult?.code || smsResult?.error_code || null;
const errorMessage = smsResult?.message || smsResult?.error_message || null;

if (errorCode || errorMessage || !sid) {
  console.error('[WF-004] CONFIRMATION SMS FAILED', JSON.stringify({
    customerPhone: $('Code: Build Confirmation SMS').first().json.customerPhone,
    tenantId: $('Code: Build Confirmation SMS').first().json.tenantId,
    errorCode, errorMessage
  }));
}

